from typing import List
import heapq

def solve(grid: List[List[int]], k: int) -> int:
    m, n = len(grid), len(grid[0])
    # Priority queue: (cost, row, col, transports_used)
    pq = [(grid[0][0], 0, 0, 0)]
    # visited[i][j][k] = minimum cost to reach (i, j) with k transports used
    visited = [[[float('inf')] * (k + 1) for _ in range(n)] for _ in range(m)]
    visited[0][0][0] = grid[0][0]

    directions = [(0, 1), (1, 0)]

    while pq:
        cost, row, col, transports = heapq.heappop(pq)
        if row == m - 1 and col == n - 1:
            return cost
        if cost > visited[row][col][transports]:
            continue

        # Regular moves
        for dr, dc in directions:
            new_row, new_col = row + dr, col + dc
            if 0 <= new_row < m and 0 <= new_col < n:
                new_cost = cost + grid[new_row][new_col]
                if new_cost < visited[new_row][new_col][transports]:
                    visited[new_row][new_col][transports] = new_cost
                    heapq.heappush(pq, (new_cost, new_row, new_col, transports))

        # Teleportation
        if transports < k:
            for x in range(m):
                for y in range(n):
                    if grid[x][y] <= grid[row][col]:
                        if cost < visited[x][y][transports + 1]:
                            visited[x][y][transports + 1] = cost
                            heapq.heappush(pq, (cost, x, y, transports + 1))

    return -1
