from collections import deque
from typing import List

def solve(grid: List[List[int]], k: int) -> int:
    m, n = len(grid), len(grid[0])
    visited = [[[float('inf')] * (k + 1) for _ in range(n)] for _ in range(m)]
    queue = deque([(0, 0, 0, 0)])  # (row, col, cost, transports)
    directions = [(0, 1), (1, 0)]

    while queue:
        row, col, cost, transports = queue.popleft()
        if row == m - 1 and col == n - 1:
            return cost
        if visited[row][col][transports] < cost:
            continue
        # Regular moves
        for dr, dc in directions:
            new_row, new_col = row + dr, col + dc
            if 0 <= new_row < m and 0 <= new_col < n:
                new_cost = cost + grid[new_row][new_col]
                if new_cost < visited[new_row][new_col][transports]:
                    visited[new_row][new_col][transports] = new_cost
                    queue.append((new_row, new_col, new_cost, transports))
        # Teleportation
        if transports < k:
            for x in range(m):
                for y in range(n):
                    if grid[x][y] <= grid[row][col]:
                        if cost < visited[x][y][transports + 1]:
                            visited[x][y][transports + 1] = cost
                            queue.append((x, y, cost, transports + 1))
    return -1
